import re, collections

cnt = collections.Counter()
with open('/tmp/all_bash_cmds.txt') as fh:
    lines = fh.read().split('\n')

# split on the original command boundaries is lost (multiline cmds collapsed); treat each line, but also split on pipes/&&/;
SKIP_PREFIX = {'sudo','timeout','command','nohup','nice','env','xargs','time'}

def first_segment(cmd):
    # split on && || | ; and take pieces, but we mainly want the leading token of the whole command
    return cmd

for raw in lines:
    raw = raw.strip()
    if not raw:
        continue
    # break into sub-commands by control operators
    parts = re.split(r'\|\||&&|;|\n|\|', raw)
    for p in parts:
        p = p.strip()
        if not p:
            continue
        toks = p.split()
        # strip env var assignments like FOO=bar
        i = 0
        while i < len(toks) and re.match(r'^[A-Za-z_][A-Za-z0-9_]*=', toks[i]):
            i += 1
        # strip prefix wrappers
        while i < len(toks) and toks[i] in SKIP_PREFIX:
            i += 1
            # skip numeric arg of timeout
            if i < len(toks) and re.match(r'^[0-9]', toks[i]):
                i += 1
        if i >= len(toks):
            continue
        cmd = toks[i]
        # strip path
        cmd_base = cmd.split('/')[-1]
        sub = toks[i+1] if i+1 < len(toks) else ''
        # for these, keep two tokens
        two = {'git','gh','docker','kubectl','cargo','go','npm','pnpm','yarn','bun','R','Rscript','air','devtools'}
        if cmd_base in two and sub and not sub.startswith('-'):
            key = f"{cmd_base} {sub}"
        else:
            key = cmd_base
        cnt[key] += 1

for k,v in cnt.most_common(60):
    print(f"{v:5d}  {k}")
PY

